import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const TELEGRAM_TOKEN = Deno.env.get("TELEGRAM_BOT_TOKEN");
const GEMINI_API_KEY = Deno.env.get("GEMINI_API_KEY");
const SUPABASE_URL = Deno.env.get("SUPABASE_URL");
const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");

const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY);

Deno.serve(async (req) => {
  try {
    const update = await req.json();
    const chatId = update.message?.chat.id;
    const userText = update.message?.text;

    if (!chatId || !userText) return new Response("ok");

    // 1. Fetch last 10 messages from Supabase for context
    const { data: history } = await supabase
      .from("chat_history")
      .select("role, content")
      .eq("user_id", chatId)
      .order("created_at", { ascending: true })
      .limit(10);

    // 2. Format history for Gemini
    const contents = history.map(h => ({
      role: h.role,
      parts: [{ text: h.content }]
    }));

    // Add the new user message
    contents.push({ role: "user", parts: [{ text: userText }] });

    // 3. Call Gemini API
    const geminiRes = await fetch(
      `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${GEMINI_API_KEY}`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ contents })
      }
    );

    const geminiData = await geminiRes.json();
    const botResponse = geminiData.candidates[0].content.parts[0].text;

    // 4. Save both messages to Supabase
    await supabase.from("chat_history").insert([
      { user_id: chatId, role: "user", content: userText },
      { user_id: chatId, role: "model", content: botResponse }
    ]);

    // 5. Send response to Telegram
    await fetch(`https://api.telegram.org/bot${TELEGRAM_TOKEN}/sendMessage`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        chat_id: chatId,
        text: botResponse,
      }),
    });

    return new Response("ok");
  } catch (err) {
    console.error(err);
    return new Response("error");
  }
});

