import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const TELEGRAM_TOKEN = Deno.env.get("TELEGRAM_BOT_TOKEN");
const GEMINI_API_KEY = Deno.env.get("GEMINI_API_KEY");

Deno.serve(async (req) => {
  try {
    const update = await req.json();
    const message = update.message;
    if (!message || !message.text) return new Response("ok");

    const chatId = message.chat.id;
    const text = message.text;

    // Command format: /fetch @username
    if (text.startsWith("/fetch")) {
      const parts = text.split(" ");
      if (parts.length < 2) {
        await sendMessage(chatId, "Please provide a channel handle. Example: `/fetch @durov` ");
        return new Response("ok");
      }

      let channelHandle = parts[1].replace("@", "");
      await sendMessage(chatId, `🔍 Accessing public data for @${channelHandle}...`);

      // 1. Fetch the Public Telegram Web Preview
      const response = await fetch(`https://t.me/s/${channelHandle}`);
      const html = await response.text();

      // 2. Extract messages using Regex (A simple way to parse HTML on mobile)
      // This looks for the text inside the Telegram message bubbles
      const messageRegex = /<div class="tgme_widget_message_text[^>]*>([\s\S]*?)<\/div>/g;
      let matches;
      let channelContent = [];

      while ((matches = messageRegex.exec(html)) !== null) {
        // Clean up HTML tags like <br> or <b> from the scraped text
        const cleanText = matches[1].replace(/<[^>]*>?/gm, '');
        channelContent.push(cleanText);
      }

      if (channelContent.length === 0) {
        await sendMessage(chatId, "❌ Could not find any recent public messages. Is the channel private or restricted?");
        return new Response("ok");
      }

      // Take the last 10 messages
      const recentMessages = channelContent.slice(-10).join("\n---\n");

      // 3. Send to Gemini for Summarization
      const prompt = `The following are the latest posts from the Telegram channel @${channelHandle}. 
      Please provide a bulleted summary of the most important news or updates mentioned here:

      ${recentMessages}`;

      const geminiRes = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${GEMINI_API_KEY}`,
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            contents: [{ parts: [{ text: prompt }] }]
          })
        }
      );

      const geminiData = await geminiRes.json();
      const summary = geminiData.candidates[0].content.parts[0].text;

      // 4. Send the result back to you
      await sendMessage(chatId, `📝 **Summary for @${channelHandle}:**\n\n${summary}`);
      return new Response("ok");
    }

    return new Response("ok");
  } catch (err) {
    console.error(err);
    return new Response("error");
  }
});

async function sendMessage(chatId, text) {
  await fetch(`https://api.telegram.org/bot${TELEGRAM_TOKEN}/sendMessage`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      chat_id: chatId,
      text: text,
      parse_mode: "Markdown"
    }),
  });
}

